#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K; scanf("%lld %lld", &N, &K);
        long long minSum = K * (K + 1) / 2;
        if(N >= minSum) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

